$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$sandbox=Join-Path ([IO.Path]::GetTempPath()) ('ueef-evidence-'+[guid]::NewGuid().ToString('N'));try{New-Item -ItemType Directory -Path $sandbox|Out-Null;$script=Join-Path $root 'scripts\export-ueef-evidence.ps1';$preview=& $script -RepositoryPath $root -IncludeMemorySummary -Task 'release evidence' -Preview|ConvertFrom-Json;if($preview.schemaVersion -ne 2 -or !$preview.provenance.runtimeVersion -or !$preview.preview -or $null -eq $preview.memorySummary -or $null -eq $preview.preflight){throw 'Evidence preview contract failed.'};$output=Join-Path $sandbox 'evidence.json';& $script -RepositoryPath $root -OutputPath $output|Out-Null;$r=Get-Content $output -Raw|ConvertFrom-Json;if($r.schemaVersion -ne 2 -or !$r.provenance.runtimeVersion){throw 'Evidence export contract failed.'};Write-Host 'Evidence export tests passed'}finally{if(Test-Path $sandbox){Remove-Item $sandbox -Recurse -Force}}
